import numpy as np, re, csv, os
from pathlib import Path
from scipy.optimize import least_squares

base = Path('/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited')

def load_tsv(path):
    with open(path, newline='') as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        rh = header[1:]
        parsed = [re.search(r'[-+]?\d*\.?\d+(?:[eE][-+]?\d+)?', h) for h in rh]
        params = [float(m.group()) for m in parsed] if all(m for m in parsed) else [float(i+1) for i in range(len(rh))]
        rows = [r for r in reader if r]
    feats, tgts = [], []
    for row in rows:
        for p, v in zip(params, row[1:]):
            if v.strip().lower() not in ('', 'nan'):
                feats.append([float(row[0]), p])
                tgts.append(float(v))
    arr = np.array(feats)
    return arr[:,0], arr[:,1], np.array(tgts)

def nmse_fn(y_true, y_pred):
    var = np.var(y_true)
    if var < 1e-12: return 0.0
    return float(np.mean((y_true - y_pred)**2) / var)

def eval_model(model_fn, p0, datasets, label):
    results = []
    for path in datasets:
        x0,x1,y = load_tsv(path)
        X = np.column_stack([x0,x1])
        try:
            res = least_squares(lambda t: model_fn(X,t)-y, p0, loss='soft_l1', max_nfev=300, method='trf')
            yp = model_fn(X, res.x)
            results.append(nmse_fn(y, yp))
        except:
            results.append(float('nan'))
    finite = [v for v in results if np.isfinite(v)]
    print(f'{label}: n={len(finite)}/42, mean={np.mean(finite):.4f}, max={max(finite):.4f}')

datasets = []
for root, dirs, files in os.walk(base):
    if 'fit.tsv' in files:
        datasets.append(Path(root)/'fit.tsv')
datasets.sort()

# Current: c0/(1+exp(c1-c2*x0-c3*x1))+c4  complexity=19, 5 params
def m_curr(X,t):
    c0,c1,c2,c3,c4=t; x0,x1=X[:,0],X[:,1]
    return c0/(1+np.exp(np.clip(c1-c2*x0-c3*x1,-500,500)))+c4

# Simpler: c0/(1+exp(c1-c2*x0))+c3  complexity~14, 4 params - drop x1
def m_4p(X,t):
    c0,c1,c2,c3=t; x0,x1=X[:,0],X[:,1]
    return c0/(1+np.exp(np.clip(c1-c2*x0,-500,500)))+c3

# c0/(1+exp(c1*(c2-x0)))+c3  complexity~14, 4 params - factored form
def m_factored(X,t):
    c0,c1,c2,c3=t; x0,x1=X[:,0],X[:,1]
    return c0/(1+np.exp(np.clip(c1*(c2-x0),-500,500)))+c3

eval_model(m_curr,     [1.0,14.0,9e-4,0.001,0.0], datasets, 'curr(5p,cpx=19)')
eval_model(m_4p,       [1.0,14.0,9e-4,0.0],        datasets, '4p_no_x1(cpx~14)')
eval_model(m_factored, [1.0,1e-3,1e4,0.0],          datasets, '4p_factored(cpx~14)')
